    my ($filename) = @_;

    # Open the PDF file
    my $pdf = PDF::API2->open($filename);

    # Create a text extractor object
    my $text_extractor = PDF::Text::Simple->new($pdf);

    # Initialize variables to store extracted information
    my $author = '';
